const response = items[0].json;
let allData = response.data || [];
const nextUrl = response.paging?.next || null;
return [{ json: { allData: allData, nextUrl: nextUrl, pageCount: 1 } }];

const previousNode = $node["Has More Pages?"].json;
const previousData = previousNode.allData || [];
const pageCount = previousNode.pageCount || 1;
const currentResponse = items[0].json;
const newData = currentResponse.data || [];
const allData = [...previousData, ...newData];
const nextUrl = currentResponse.paging?.next || null;
if (pageCount >= 50) {
  return [{ json: { allData: allData, nextUrl: null, pageCount: pageCount + 1 } }];
}
return [{ json: { allData: allData, nextUrl: nextUrl, pageCount: pageCount + 1 } }];

const allData = items[0].json.allData || [];
if (allData.length === 0) return [{ json: { message: 'No data for yesterday' } }];
return allData.map(item => ({ json: item }));

const syncedAt = new Date().toISOString();
return items.map(item => {
  const d = item.json;

  // Extract purchases from actions
  const purchaseAction = (d.actions || []).find(a => a.action_type === 'purchase');
  const purchases = purchaseAction ? parseInt(purchaseAction.value) || 0 : 0;

  // Extract purchase value from action_values
  const purchaseValueAction = (d.action_values || []).find(a => a.action_type === 'purchase');
  const purchaseValue = purchaseValueAction ? parseFloat(purchaseValueAction.value) || 0 : 0;

  // Calculate ROAS
  const spend = parseFloat(d.spend) || 0;
  const roas = spend > 0 ? Math.round((purchaseValue / spend) * 100) / 100 : 0;

  return { json: {
    date: d.date_start,
    campaign_id: d.campaign_id || '',
    campaign_name: d.campaign_name || '',
    adset_id: d.adset_id || '',
    adset_name: d.adset_name || '',
    ad_id: d.ad_id || '',
    ad_name: d.ad_name || '',
    spend: spend,
    impressions: parseInt(d.impressions) || 0,
    clicks: parseInt(d.clicks) || 0,
    reach: parseInt(d.reach) || 0,
    purchases: purchases,
    purchase_value: purchaseValue,
    purchase_roas: roas,
    account_currency: d.account_currency || 'CAD',
    synced_at: syncedAt
  }};
});
